# Extract label/edge-text contents: node labels [..] (..) {..} ((..)) [(..)] and edge text |"..."| or |..|
# Then check for breaking chars within those.
# Breaking chars per task: parentheses, wrong square brackets, colon, semicolon, slash, quotes, angle brackets, curly braces inside text.
breaking = set('():;/<>{}"\'')
# Note: quotes used to WRAP edge labels are fine; we check chars INSIDE the wrapper.

def find_issues(lineno, ln):
    issues=[]
    s = ln
    # 1) edge labels: |...| 
    for m in re.finditer(r'\|([^|]*)\|', s):
        inner = m.group(1)
        # strip surrounding quotes if present (quoting is the SAFE form)
        core = inner
        quoted = False
        if len(inner)>=2 and inner[0]=='"' and inner[-1]=='"':
            core = inner[1:-1]; quoted=True
        bad = [c for c in core if c in breaking]
        if bad:
            issues.append(("edge-label", inner, set(bad), quoted))
    # 2) node labels: NAME[...] NAME(...) NAME{...} NAME[(...)] NAME[[...]] etc.
    # Match identifier followed by bracket group
    for m in re.finditer(r'[A-Za-z0-9_]+(\[\[.*?\]\]|\[\(.*?\)\]|\(\(.*?\)\)|\[.*?\]|\(.*?\)|\{.*?\})', s):
        grp = m.group(1)
        # determine wrapper and inner
        inner=None; kind=None
        if grp.startswith('[[') and grp.endswith(']]'):
            inner=grp[2:-2]; kind='subroutine[[]]'
        elif grp.startswith('[(') and grp.endswith(')]'):
            inner=grp[2:-2]; kind='cylinder[()]'
        elif grp.startswith('((') and grp.endswith('))'):
            inner=grp[2:-2]; kind='circle(())'
        elif grp.startswith('[') and grp.endswith(']'):
            inner=grp[1:-1]; kind='rect[]'
        elif grp.startswith('(') and grp.endswith(')'):
            inner=grp[1:-1]; kind='round()'
        elif grp.startswith('{') and grp.endswith('}'):
            inner=grp[1:-1]; kind='diamond{}'
        if inner is not None:
            core=inner; quoted=False
            if len(inner)>=2 and inner[0]=='"' and inner[-1]=='"':
                core=inner[1:-1]; quoted=True
            bad=[c for c in core if c in breaking]
            if bad:
                issues.append((kind, inner, set(bad), quoted))
    return issues

anyfound=False
